select * from ( WITH SOURCE AS (SELECT TBCI.ID, CASE WHEN TBCI.SOURCE = '30' THEN '货转' WHEN TBCI.SOURCE = '50' THEN '混配' when TBCI.SOURCE = '20' then '集港' when tbci.SOURCE = '10' then '卸船' ELSE COALESCE(TBCI.IS_TOS, CASE WHEN TBT.TYPE = '拆箱集港' THEN '集港' ELSE TBT.TYPE END) END "source" FROM T_BUS_CARGO_INFO TBCI LEFT JOIN T_BUS_TRUST TBT ON TBCI.TRUST_ID = TBT.ID), STORAGE_RATE AS (SELECT TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE, TBCR.FREE_STORAGE_DAYS FROM T_BUS_CONTRACT_COMPANY TBCC JOIN T_BUS_CONTRACT TBC ON (TBC.STATUS = '20' AND TBCC.CONTRACT_ID = TBC.ID) JOIN T_BUS_CONTRACT_RATE TBCR ON (TBCR.TYPE = '10' AND TBCR.RATE_ITEM_CODE = 'MS00240' AND TBC.ID = TBCR.CONTRACT_ID) GROUP BY TBCC.COMPANY_ID, TBC.CUSTOMER_ID, TBC.START_TIME, TBC.END_TIME, TBCR.CARGO_CODE, TBCR.FREE_STORAGE_DAYS ORDER BY TBCR.FREE_STORAGE_DAYS DESC), tmp_COST_STORAGE_FEE as (select TCSS.CARGO_INFO_ID,TCSS.REDUCE_TYPE from T_COST_STORAGE_SETTLE TCSS join (select CARGO_INFO_ID,max(REDUCE_TYPE) reduce_type,max(CREATE_TIME) CREATE_TIME from T_COST_STORAGE_SETTLE group by CARGO_INFO_ID) tmp_TCSS on tmp_TCSS.CARGO_INFO_ID = TCSS.CARGO_INFO_ID and TCSS.CREATE_TIME = tmp_TCSS.CREATE_TIME where TCSS.REDUCE_TYPE is not null ) SELECT SOURCE."source", TBCI.ID, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, CASE WHEN MC.SIGN IS NOT NULL THEN TBCI.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TBCI.CARGO_NAME END "cargoName", DECODE(MC.WORK_TYPE, '1', '件杂', '2', '散杂', '3', '木材', NULL) "workTypeLabel", TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, CASE WHEN SOURCE."source" = '卸船' THEN TDS.SHIP_NAME || '_' || TDSI.VOYAGE END "shipNameVoyage", TDS.SCN, TDS.BERTH_TIME, TDSI.WORK_START_TIME, TDSI.WORK_END_TIME, TDS.LEAVE_BERTH_TIME, TDSI.LOAD_UNLOAD, CASE TO_CHAR(TDSI.IMP_EXP) WHEN 'IN' THEN '进口' WHEN 'OUT' THEN '出口' END "impExpLabel", TBCI.TRADE_TYPE, WEIGH_JG."minWeighOutDt", TBCI.TRANSFER_DATE, TBCMR.MIX_TIME, TBCI.CLEAR_BY_NAME, TBCI.REAL_CLEAR_DATE, TBT.TRUST_NO, TBT.RELEASE_TIME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, decode(tmp_cc.reduce_type, '3', '是', '否') "isReduceTypeThree", TRUNC(NVL( TBCI.REAL_CLEAR_DATE, SYSDATE) - CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END - CASE SOURCE."source" WHEN '卸船' THEN MIN(STORAGE_RATE.FREE_STORAGE_DAYS) WHEN '集港' THEN MIN(STORAGE_RATE.FREE_STORAGE_DAYS) WHEN '货转' THEN TBCI.RESIDUE_STORAGE WHEN '混配' THEN TBCI.MIX_FREE_STORAGE_DAYS END ,0) "overdueDays", TBCI.STATEMENT_STATUS_CODE STATEMENT_STATUS, CASE TO_CHAR(TBCI.IS_CLEAR) WHEN '0' THEN '否' WHEN '1' THEN '是' END "isClearLabel" FROM T_BUS_CARGO_INFO TBCI JOIN SOURCE ON (TBCI.ID = SOURCE.ID AND SOURCE."source" IN ('卸船', '集港', '货转', '混配')) LEFT JOIN T_BUS_TRUST TBT ON TBCI.TRUST_ID = TBT.ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TBCI.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID JOIN M_CARGO MC ON (MC.DEL_FLAG = '0' AND TBCI.CARGO_CODE = MC.CARGO_CODE) LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) "minWeighOutDt" FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) WEIGH_JG ON TBCI.ID = WEIGH_JG.CARGO_INFO_ID left join tmp_COST_STORAGE_FEE tmp_cc on tmp_cc.CARGO_INFO_ID = TBCI.ID LEFT JOIN T_BUS_CARGO_MIX_RECORD TBCMR ON TBCI.ID = TBCMR.CARGO_INFO_ID LEFT JOIN STORAGE_RATE ON (TBCI.COMPANY_ID = STORAGE_RATE.COMPANY_ID AND TBCI.CARGO_OWNER_ID = STORAGE_RATE.CUSTOMER_ID AND to_char(CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END,'yyyy-MM-dd') >= to_char(STORAGE_RATE.START_TIME,'yyyy-MM-dd') AND to_char(CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END,'yyyy-MM-dd') <= to_char(STORAGE_RATE.END_TIME,'yyyy-MM-dd') AND TBCI.CARGO_CODE = STORAGE_RATE.CARGO_CODE)
AND TBCI.IS_SETTLE_STORAGE = '1'
AND TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND TBCI.CARGO_OWNER_ID = #{cargoOwnerId,jdbcType=BIGINT}
AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike,jdbcType=VARCHAR}
AND TBCI.COMPANY_ID = #{companyId,jdbcType=VARCHAR}
AND TDSI.SHIP_STATUS_CODE = #{shipStatusCode,jdbcType=BIGINT}
AND TBCI.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}
AND TDS.LEAVE_BERTH_TIME >= #{beginLeaveBerthTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_BERTH_TIME <= #{endLeaveBerthTime,jdbcType=TIMESTAMP}
AND NVL2(TBCI.CLEAR_DATE, TBCI.REAL_CLEAR_DATE, SYSDATE) - CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END - CASE SOURCE."source" WHEN '卸船' THEN STORAGE_RATE.FREE_STORAGE_DAYS WHEN '集港' THEN STORAGE_RATE.FREE_STORAGE_DAYS WHEN '货转' THEN TBCI.RESIDUE_STORAGE WHEN '混配' THEN TBCI.MIX_FREE_STORAGE_DAYS END > 0
AND NVL2(TBCI.CLEAR_DATE, TBCI.REAL_CLEAR_DATE, SYSDATE) - CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END - CASE SOURCE."source" WHEN '卸船' THEN STORAGE_RATE.FREE_STORAGE_DAYS WHEN '集港' THEN STORAGE_RATE.FREE_STORAGE_DAYS WHEN '货转' THEN TBCI.RESIDUE_STORAGE WHEN '混配' THEN TBCI.MIX_FREE_STORAGE_DAYS END <= 0
AND TBCI.IS_CLEAR = #{isClear,jdbcType=VARCHAR}
AND TDSI.IMP_EXP = #{impExp,jdbcType=VARCHAR}
AND TDS.SCN LIKE #{scnLike,jdbcType=VARCHAR}
AND TBCI.CONTRACT_CODE LIKE #{contractCodeLike,jdbcType=VARCHAR}
AND MC.WORK_TYPE = #{workType,jdbcType=VARCHAR}
AND TBCI.STATEMENT_STATUS_CODE = #{statementStatus}
AND decode(tmp_cc.reduce_type, '3', '是', '否') = '是'
AND decode(tmp_cc.reduce_type, '3', '是', '否') = '否'
GROUP BY SOURCE."source", TBCI.ID, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, MC.SIGN, TBCI.CARGO_NAME, MC.WORK_TYPE, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TDS.SHIP_NAME, TDSI.VOYAGE, TDS.SCN, TDS.BERTH_TIME, TDSI.WORK_START_TIME, TDSI.WORK_END_TIME, TDS.LEAVE_BERTH_TIME, TDSI.LOAD_UNLOAD, TDSI.IMP_EXP, TBCI.TRADE_TYPE, WEIGH_JG."minWeighOutDt", TBCI.TRANSFER_DATE, TBCMR.MIX_TIME, TBCI.CLEAR_BY_NAME, TBCI.REAL_CLEAR_DATE, TBT.TRUST_NO, TBT.RELEASE_TIME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.CLEAR_DATE, TBCI.RESIDUE_STORAGE, TBCI.MIX_FREE_STORAGE_DAYS, TBCI.STATEMENT_STATUS_CODE,TBCI.IS_CLEAR, TBCI.CREATE_TIME,tmp_cc.reduce_type
ORDER BY NVL2(TBCI.CLEAR_DATE, TBCI.REAL_CLEAR_DATE, SYSDATE) - CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END - CASE SOURCE."source" WHEN '卸船' THEN MIN(STORAGE_RATE.FREE_STORAGE_DAYS) WHEN '集港' THEN MIN(STORAGE_RATE.FREE_STORAGE_DAYS) WHEN '货转' THEN TBCI.RESIDUE_STORAGE WHEN '混配' THEN TBCI.MIX_FREE_STORAGE_DAYS END DESC NULLS LAST
ORDER BY TBCI.CREATE_TIME DESC
)

SELECT ID,CAL_END_DATE
FROM T_BUS_STACK_FEE_REDUCE
WHERE CARGO_INFO_ID = #{id,jdbcType=BIGINT}

