UPDATE T_COST_STATEMENT SET STATUS = #{status, jdbcType=VARCHAR}
, STATEMENT_BY = #{statementBy,jdbcType=BIGINT}, STATEMENT_BY_NAME = #{statementByName,jdbcType=VARCHAR}, STATEMENT_TIME = #{statementTime,jdbcType=TIMESTAMP}
, SETTLEMENT_BASIS_CODE = #{settlementBasisCode,jdbcType=VARCHAR}, SETTLEMENT_BASIS_NAME = #{settlementBasisName,jdbcType=VARCHAR}, STATEMENT_BY = #{statementBy,jdbcType=BIGINT}, STATEMENT_BY_NAME = #{statementByName,jdbcType=VARCHAR}, STATEMENT_TIME = #{statementTime,jdbcType=TIMESTAMP}, REVIEW_BY = #{reviewBy,jdbcType=BIGINT}, REVIEW_BY_NAME = #{reviewByName,jdbcType=VARCHAR}, REVIEW_TIME = #{reviewTime,jdbcType=TIMESTAMP}
, RECEIPT_REMARK = #{receiptRemark,jdbcType=VARCHAR}, TAX_INVOICE_CODE = #{taxInvoiceCode,jdbcType=VARCHAR}, TAX_INVOICE_NAME = #{taxInvoiceName,jdbcType=VARCHAR}, REVIEW_BY = #{reviewBy,jdbcType=BIGINT}, REVIEW_BY_NAME = #{reviewByName,jdbcType=VARCHAR}, REVIEW_TIME = #{reviewTime,jdbcType=TIMESTAMP}, CONFIRM_BY = #{confirmBy,jdbcType=BIGINT}, CONFIRM_BY_NAME = #{confirmByName,jdbcType=VARCHAR}, CONFIRM_TIME = #{confirmTime,jdbcType=TIMESTAMP}
, RECEIPT_REMARK = #{receiptRemark,jdbcType=VARCHAR}, TAX_INVOICE_CODE = #{taxInvoiceCode,jdbcType=VARCHAR}, TAX_INVOICE_NAME = #{taxInvoiceName,jdbcType=VARCHAR}, CONFIRM_BY = #{confirmBy,jdbcType=BIGINT}, CONFIRM_BY_NAME = #{confirmByName,jdbcType=VARCHAR}, CONFIRM_TIME = #{confirmTime,jdbcType=TIMESTAMP}
WHERE ID = #{id, jdbcType=BIGINT}

mapper.select:
WITH SOURCE AS (SELECT TBCI.ID, CASE WHEN TBCI.SOURCE = '30' THEN '货转' WHEN TBCI.SOURCE = '50' THEN '混配'
when TBCI.SOURCE = '20' then '集港' when tbci.SOURCE = '10' then '卸船' ELSE COALESCE(TBCI.IS_TOS, CASE WHEN TBT.TYPE = '拆箱集港' THEN '集港' ELSE TBT.TYPE END) END "source" FROM T_BUS_CARGO_INFO TBCI LEFT JOIN T_BUS_TRUST TBT ON TBCI.TRUST_ID = TBT.ID) SELECT SOURCE."source", TCSS.ID TCSS_ID, TCS.ID STATEMENT_ID, TCS.STATEMENT_NO, TBCI.ID, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, CASE WHEN MC.SIGN IS NOT NULL THEN TBCI.CARGO_NAME || '(' || MC.SIGN || ')' ELSE TBCI.CARGO_NAME END "cargoName", DECODE(MC.WORK_TYPE, '1', '件杂', '2', '散杂', '3', '木材', NULL) "workTypeLabel", TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, CASE WHEN SOURCE."source" = '卸船' THEN TDS.SHIP_NAME || '_' || TDSI.VOYAGE END "shipNameVoyage", TDS.SCN, TCSS.amount, TDS.BERTH_TIME, TDSI.WORK_START_TIME, TDSI.WORK_END_TIME, TDS.LEAVE_BERTH_TIME, TDSI.LOAD_UNLOAD, CASE TO_CHAR(TDSI.IMP_EXP) WHEN 'IN' THEN '进口' WHEN 'OUT' THEN '出口' END "impExpLabel", TBCI.TRADE_TYPE, WEIGH_JG."minWeighOutDt", TBCI.TRANSFER_DATE, TBCMR.MIX_TIME, TBCI.CLEAR_BY_NAME, TBCI.REAL_CLEAR_DATE, TBT.TRUST_NO, TBT.RELEASE_TIME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TCSS.END_DATE - CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END - CASE SOURCE."source" WHEN '卸船' THEN TBCR.FREE_STORAGE_DAYS WHEN '集港' THEN TBCR.FREE_STORAGE_DAYS WHEN '货转' THEN TBCI.RESIDUE_STORAGE WHEN '混配' THEN TBCI.MIX_FREE_STORAGE_DAYS END "overdueDays", CASE WHEN TCS.ID IS NOT NULL THEN to_char(TCS.STATUS) ELSE '20' END STATEMENT_STATUS,
CASE TO_CHAR(TBCI.IS_CLEAR) WHEN '0' THEN '否' WHEN '1' THEN '是' END "isClearLabel", TCS.RECEIPT_REMARK, TCSS.REJECT_REASON, TCSS.REJECT_BY_NAME, TCSS.REJECT_TIME, TCSS.CREATE_BY_NAME, TCSS.CREATE_TIME, decode(TCSS.REDUCE_TYPE,'3','是','否') "isReduceTypeThree" FROM T_COST_STORAGE_SETTLE TCSS LEFT JOIN T_COST_STATEMENT_DETAIL TCSD on TCSS.ID = TCSD.BUSINESS_ID LEFT JOIN T_COST_STATEMENT TCS on TCSD.STATEMENT = TCS.ID LEFT JOIN T_BUS_CARGO_INFO TBCI ON TBCI.ID = TCSS.CARGO_INFO_ID JOIN SOURCE ON (TBCI.ID = SOURCE.ID AND SOURCE."source" IN ('卸船', '集港', '货转', '混配')) LEFT JOIN (SELECT CARGO_INFO_ID, MAX(IS_FINAL) IS_FINAL FROM T_COST_STORAGE_SETTLE GROUP BY CARGO_INFO_ID ) TCSS_1 ON TCSS_1.CARGO_INFO_ID = TBCI.ID LEFT JOIN T_BUS_TRUST TBT ON TBCI.TRUST_ID = TBT.ID LEFT JOIN T_DIS_SHIPVOYAGE TDS ON TBCI.SHIPVOYAGE_ID = TDS.ID LEFT JOIN T_DIS_SHIPVOYAGE_ITEM TDSI ON TBCI.SHIPVOYAGE_ITEM_ID = TDSI.ID JOIN M_CARGO MC ON (MC.DEL_FLAG = '0' AND TBCI.CARGO_CODE = MC.CARGO_CODE) LEFT JOIN (SELECT TEMP.CARGO_INFO_ID, MIN(TEMP.WEIGH_OUT_DT) "minWeighOutDt" FROM (SELECT TEMP.CARGO_INFO_ID, VWI.WEIGH_OUT_DT FROM (SELECT TBTC.BUSINESS_NO, TBTC.CARGO_INFO_ID FROM T_BUS_TRUST_CARGO TBTC JOIN T_BUS_TRUST TBT ON TBTC.TRUST_ID = TBT.ID AND TBT.TYPE IN ('集港', '拆箱集港')) TEMP JOIN V_WEIGHT_INFO VWI ON VWI.IS_OLD = '否' AND TEMP.BUSINESS_NO = VWI.PLAN_NO UNION ALL SELECT TO_NUMBER(VWI2.CARGO_INFO_ID), VWI2.WEIGH_OUT_DT FROM V_WEIGHT_INFO VWI2 WHERE VWI2.IS_OLD = '是' AND VWI2.PLAN_TYPE IN ('集港', '拆箱集港')) TEMP GROUP BY TEMP.CARGO_INFO_ID) WEIGH_JG ON TBCI.ID = WEIGH_JG.CARGO_INFO_ID LEFT JOIN T_BUS_CARGO_MIX_RECORD TBCMR ON TBCI.ID = TBCMR.CARGO_INFO_ID left join T_BUS_CONTRACT TBC on TCSS.CONTRACT_ID = TBC.ID left join T_BUS_CONTRACT_RATE TBCR on (TBC.ID = TBCR.CONTRACT_ID and TBCI.CARGO_CODE = TBCR.CARGO_CODE and TBCR.RATE_ITEM_CODE = 'MS00240')
TBCI.IS_SETTLE_STORAGE !='0'
and TCSS.AMOUNT > 0
AND TBCI.SHIPVOYAGE_ITEM_ID = #{shipvoyageItemId,jdbcType=BIGINT}
AND TBCI.CARGO_OWNER_ID = #{cargoOwnerId,jdbcType=BIGINT}
AND TBCI.CARGO_INFO_NO LIKE #{cargoInfoNoLike,jdbcType=VARCHAR}
AND TBCI.COMPANY_ID = #{companyId,jdbcType=VARCHAR}
AND TDSI.SHIP_STATUS_CODE = #{shipStatusCode,jdbcType=BIGINT}
AND TBCI.CARGO_NAME LIKE #{cargoNameLike, jdbcType=VARCHAR}
AND TDS.LEAVE_BERTH_TIME >= #{beginLeaveBerthTime,jdbcType=TIMESTAMP}
AND TDS.LEAVE_BERTH_TIME <= #{endLeaveBerthTime,jdbcType=TIMESTAMP}
AND NVL2(TBCI.CLEAR_DATE, TBCI.REAL_CLEAR_DATE, SYSDATE) - CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END - CASE SOURCE."source" WHEN '卸船' THEN STORAGE_RATE.FREE_STORAGE_DAYS WHEN '集港' THEN STORAGE_RATE.FREE_STORAGE_DAYS WHEN '货转' THEN TBCI.RESIDUE_STORAGE WHEN '混配' THEN TBCI.MIX_FREE_STORAGE_DAYS END > 0
AND NVL2(TBCI.CLEAR_DATE, TBCI.REAL_CLEAR_DATE, SYSDATE) - CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END - CASE SOURCE."source" WHEN '卸船' THEN STORAGE_RATE.FREE_STORAGE_DAYS WHEN '集港' THEN STORAGE_RATE.FREE_STORAGE_DAYS WHEN '货转' THEN TBCI.RESIDUE_STORAGE WHEN '混配' THEN TBCI.MIX_FREE_STORAGE_DAYS END <= 0
AND TBCI.IS_CLEAR = #{isClear,jdbcType=VARCHAR}
AND TDSI.IMP_EXP = #{impExp,jdbcType=VARCHAR}
AND TDS.SCN LIKE #{scnLike,jdbcType=VARCHAR}
AND TBCI.CONTRACT_CODE LIKE #{contractCodeLike,jdbcType=VARCHAR}
AND MC.WORK_TYPE = #{workType,jdbcType=VARCHAR}
AND CASE WHEN TCS.ID IS NOT NULL THEN to_char(TCS.STATUS) ELSE '20' END = #{statementStatus}
AND decode(TCSS.REDUCE_TYPE,'3','是','否') = '是'
AND decode(TCSS.REDUCE_TYPE,'3','是','否') = '否'
and (TCSS.AMOUNT=0 or TCSS.AMOUNT is null)
and TCSS.AMOUNT > 0
GROUP BY TCS.STATEMENT_NO,TCS.RECEIPT_REMARK, TCSS.CREATE_BY_NAME, TCSS.CREATE_TIME, CASE WHEN TCS.ID IS NOT NULL THEN to_char(TCS.STATUS) ELSE '20' END, TCS.ID, TCSS.ID, SOURCE."source",TCSS.amount,TCSS.REJECT_REASON,TCSS.REJECT_BY_NAME,TCSS.REJECT_TIME, TBCI.ID, TBCI.CARGO_INFO_NO, TBCI.CARGO_OWNER_ID, TBCI.CARGO_OWNER_NAME, MC.SIGN, TBCI.CARGO_NAME, MC.WORK_TYPE, TBCI.SHIPVOYAGE_ID, TBCI.SHIPVOYAGE_ITEM_ID, TDS.SHIP_NAME, TDSI.VOYAGE, TDS.SCN, TDS.BERTH_TIME, TDSI.WORK_START_TIME, TDSI.WORK_END_TIME, TDS.LEAVE_BERTH_TIME, TDSI.LOAD_UNLOAD, TDSI.IMP_EXP, TBCI.TRADE_TYPE, WEIGH_JG."minWeighOutDt", TBCI.TRANSFER_DATE, TBCMR.MIX_TIME, TBCI.CLEAR_BY_NAME, TBCI.REAL_CLEAR_DATE, TBT.TRUST_NO, TBT.RELEASE_TIME, TBCI.COMPANY_ID, TBCI.COMPANY_NAME, TBCI.CLEAR_DATE, TBCI.RESIDUE_STORAGE, TBCI.MIX_FREE_STORAGE_DAYS, TBCI.IS_CLEAR,TBCR.FREE_STORAGE_DAYS, TCSS.END_DATE,TCSS.REDUCE_TYPE ORDER BY TCSS.END_DATE - CASE SOURCE."source" WHEN '卸船' THEN TDSI.WORK_START_TIME WHEN '集港' THEN WEIGH_JG."minWeighOutDt" WHEN '货转' THEN TBCI.TRANSFER_DATE WHEN '混配' THEN TBCMR.MIX_TIME END - CASE SOURCE."source" WHEN '卸船' THEN TBCR.FREE_STORAGE_DAYS WHEN '集港' THEN TBCR.FREE_STORAGE_DAYS WHEN '货转' THEN TBCI.RESIDUE_STORAGE WHEN '混配' THEN TBCI.MIX_FREE_STORAGE_DAYS END DESC NULLS LAST

